from source import longest_common_subsequence


def test_match_advances_both_strings():
    result = longest_common_subsequence('AGCAT', 'GAC')

    def is_subsequence(s, t):
        it = iter(t)
        return all(c in it for c in s)

    assert len(result) == 2 and is_subsequence(result, 'AGCAT') and is_subsequence(result, 'GAC'), (
        f"Expected a valid LCS of length 2 (e.g. 'AC' or 'GC'), got {result!r} (length {len(result)}). "
        "Bug: on a match, b is not advanced, so the same b[0] can be re-matched in deeper frames."
    )
